   814→  upgradeToGridLayout(old: any) {
   815→    let yPos = 0;
   816→    const widthFactor = GRID_COLUMN_COUNT / 12;
   817→
   818→    const maxPanelId =
   819→      max(
   820→        flattenDeep(
   821→          map(old.rows, (row) => {
   822→            return map(row.panels, 'id');
   823→          })
   824→        ).filter((id) => id != null)
   825→      ) || 0;
   826→    let nextRowId = maxPanelId + 1;
   827→
   828→    if (!old.rows) {
   829→      return;
   830→    }
   831→
   832→    // Add special "row" panels if even one row is collapsed, repeated or has visible title
   833→    const showRows = some(old.rows, (row) => row.collapse || row.showTitle || row.repeat);
   834→
   835→    for (const row of old.rows) {
   836→      if (row.repeatIteration) {
   837→        continue;
   838→      }
   839→
   840→      const height = row.height || DEFAULT_ROW_HEIGHT;
   841→      const rowGridHeight = getGridHeight(height);
   842→
   843→      const rowPanel: any = {};
   844→      let rowPanelModel: PanelModel | undefined;
   845→
   846→      if (showRows) {
   847→        // add special row panel
   848→        rowPanel.id = nextRowId;
   849→        rowPanel.type = 'row';
   850→        rowPanel.title = row.title;
   851→        rowPanel.collapsed = row.collapse;
   852→        rowPanel.repeat = row.repeat;
   853→        rowPanel.panels = [];
   854→        rowPanel.gridPos = {
   855→          x: 0,
   856→          y: yPos,
   857→          w: GRID_COLUMN_COUNT,
   858→          h: rowGridHeight,
   859→        };
   860→        rowPanelModel = new PanelModel(rowPanel);
   861→        nextRowId++;
   862→        yPos++;
